import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface WeeklyTrend {
  day: string;
  rate: number;
}

interface CurrencyExchangeData {
  currencyPair: string;
  currentRate: number;
  change: number;
  changePercent: number;
  weeklyTrend: WeeklyTrend[];
  rateTrend: number[];
}

export default function Widget() {
  const currencyData = response.data as CurrencyExchangeData;
  const isPositive = currencyData.change >= 0;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E293B' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#94A3B8' }}>
              {currencyData.currencyPair}
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ color: '#F8FAFC' }}>
              {currencyData.currentRate.toFixed(4)}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {isPositive ? <TrendingUp sx={{ fontSize: 16, color: '#10B981' }} /> : <TrendingDown sx={{ fontSize: 16, color: '#EF4444' }} />}
              <Typography variant="body2" sx={{ color: isPositive ? '#10B981' : '#EF4444' }}>
                {currencyData.change.toFixed(4)} ({currencyData.changePercent.toFixed(2)}%)
              </Typography>
            </Stack>
          </Box>

          <LineChart
            height={100}
            series={[
              {
                data: currencyData.rateTrend,
                color: '#2196F3',
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: currencyData.weeklyTrend.map((_, i) => i), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Stack direction="row" spacing={0.5}>
            {currencyData.weeklyTrend.map((trend) => (
              <Chip
                key={trend.day}
                label={`${trend.day}: ${trend.rate.toFixed(4)}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#374151', color: '#F8FAFC' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
